#!/usr/bin/env python3
import subprocess, sys, os, base64

MAIN_B64  = ''
TOKEN_B64 = ''
REQUIRED  = ['requests']
OPTIONAL  = ['pyenchant']

def install(pkg):
    subprocess.check_call([sys.executable,'-m','pip','install',pkg,'--quiet'],stdout=subprocess.DEVNULL,stderr=subprocess.DEVNULL)

def main():
    G=chr(27)+'[92m'; R=chr(27)+'[91m'; X=chr(27)+'[0m'
    here   = os.path.dirname(os.path.abspath(__file__))
    target = os.path.join(here, 'SohSocialScanMain.py')
    token_guide = os.path.join(here, 'HOW_TO_GET_TOKEN.txt')
    print()
    print("  [91mSOHSOCIALSCAN[0m")
    print("  [92mSetup[0m")
    print("  [94mgithub.com/soh4p/SohSocialScan[0m")
    print()
    print('  Location: ' + here + chr(10))
    for pkg in REQUIRED:
        try:
            print('  ▶ ' + pkg + '...', end=' ', flush=True)
            install(pkg); print(G+'✔'+X)
        except:
            print(R+'✘ FAILED - Check internet.'+X)
            input('  Enter to exit.'); sys.exit(1)
    for pkg in OPTIONAL:
        try:
            print('  ▶ ' + pkg + ' (optional)...', end=' ', flush=True)
            install(pkg); print(G+'✔'+X)
        except: print('skipped')
    print(chr(10) + '  ▶ Writing SohSocialScanMain.py...', end=' ', flush=True)
    try:
        with open(target,'w',encoding='utf-8') as f: f.write(base64.b64decode(MAIN_B64.encode('ascii')).decode('utf-8'))
        print(G+'✔'+X)
    except Exception as e: print(R+'✘ '+str(e)+X); input('Enter.'); sys.exit(1)
    print('  ▶ Writing HOW_TO_GET_TOKEN.txt...', end=' ', flush=True)
    try:
        with open(token_guide,'w',encoding='utf-8') as f: f.write(base64.b64decode(TOKEN_B64.encode('ascii')).decode('utf-8'))
        print(G+'✔'+X)
    except Exception as e: print(R+'✘ '+str(e)+X)
    print(chr(10) + '  └─ Done!  Run: python SohSocialScanMain.py' + chr(10))
    input('  Enter to close.')
    try: os.remove(os.path.abspath(__file__))
    except: pass

if __name__ == '__main__': main()